index 6e4689863407..e3d31a0afb5f 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -687,6 +687,90 @@ static Value *foldLogOpOfMaskedICmps(Value *LHS, Value *RHS, bool IsAnd,
         return Builder.CreateICmp(CC, NewAnd, CEVal);
       };

+      // Handle (A == C) | ((A & D) == E) -> (A - C) <u ((~D) + 2)
+      // and (A != C) & ((A & D) != E) -> (A - (C + (~D) + 2)) <u -((~D) + 2)
+      // when the simple equality check is adjacent to the masked range.
+      // D must have trailing zeros (D = ~P where P is a power of two),
+      // E must be aligned to D (E & ~D == 0), and C == E - 1.
+      // For example, (x == 127) | ((x & -32) == 128) -> (x - 127) <u 33.
+      // (x != 127) & ((x & -32) != 128) -> (x - 160) <u -33.
+      if (PredL == ICmpInst::ICMP_EQ && PredR == ICmpInst::ICMP_EQ) {
+        // OR-of-EQ: (A == C) | ((A & D) == E) -> (A - C) <u ((~D) + 2)
+        if (!IsAnd) {
+          if (ConstB->isAllOnes()) {
+            const APInt *ConstC, *ConstE;
+            if (match(C, m_APInt(ConstC)) && match(E, m_APInt(ConstE))) {
+              const APInt NotD = ~(*ConstD);
+              if ((NotD + 1).isPowerOf2() && (*ConstE & NotD) == 0 &&
+                  *ConstC == *ConstE - 1) {
+                // Check that the AND on the RHS has only one use.
+                if (auto *RHSInst = dyn_cast<Instruction>(RHS))
+                  if (RHSInst->getOperand(0)->hasOneUse()) {
+                    APInt RangeSize = NotD + 2;
+                    Value *NewV = Builder.CreateSub(A, C);
+                    return Builder.CreateICmp(ICmpInst::ICMP_ULT, NewV,
+                                              ConstantInt::get(A->getType(), RangeSize));
+                  }
+              }
+            }
+          } else if (ConstD->isAllOnes()) {
+            const APInt *ConstC, *ConstE;
+            if (match(C, m_APInt(ConstC)) && match(E, m_APInt(ConstE))) {
+              const APInt NotB = ~(*ConstB);
+              if ((NotB + 1).isPowerOf2() && (*ConstC & NotB) == 0 &&
+                  *ConstE == *ConstC - 1) {
+                // Check that the AND on the LHS has only one use.
+                if (auto *LHSInst = dyn_cast<Instruction>(LHS))
+                  if (LHSInst->getOperand(0)->hasOneUse()) {
+                    APInt RangeSize = NotB + 2;
+                    Value *NewV = Builder.CreateSub(A, E);
+                    return Builder.CreateICmp(ICmpInst::ICMP_ULT, NewV,
+                                              ConstantInt::get(A->getType(), RangeSize));
+                  }
+              }
+            }
+          }
+        }
+      } else if (PredL == ICmpInst::ICMP_NE && PredR == ICmpInst::ICMP_NE) {
+        // AND-of-NE: (A != C) & ((A & D) != E) -> (A - (C + (~D) + 2)) <u -((~D) + 2)
+        if (IsAnd) {
+          if (ConstB->isAllOnes()) {
+            const APInt *ConstC, *ConstE;
+            if (match(C, m_APInt(ConstC)) && match(E, m_APInt(ConstE))) {
+              const APInt NotD = ~(*ConstD);
+              if ((NotD + 1).isPowerOf2() && (*ConstE & NotD) == 0 &&
+                  *ConstC == *ConstE - 1) {
+                // Check that the AND on the RHS has only one use.
+                if (auto *RHSInst = dyn_cast<Instruction>(RHS))
+                  if (RHSInst->getOperand(0)->hasOneUse()) {
+                    APInt RangeSize = NotD + 2;
+                    APInt NewC = *ConstC + RangeSize;
+                    Value *NewV = Builder.CreateSub(A, ConstantInt::get(A->getType(), NewC));
+                    return Builder.CreateICmp(ICmpInst::ICMP_ULT, NewV,
+                                              ConstantInt::get(A->getType(), -RangeSize));
+                  }
+              }
+            }
+          } else if (ConstD->isAllOnes()) {
+            const APInt *ConstC, *ConstE;
+            if (match(C, m_APInt(ConstC)) && match(E, m_APInt(ConstE))) {
+              const APInt NotB = ~(*ConstB);
+              if ((NotB + 1).isPowerOf2() && (*ConstC & NotB) == 0 &&
+                  *ConstE == *ConstC - 1) {
+                // Check that the AND on the LHS has only one use.
+                if (auto *LHSInst = dyn_cast<Instruction>(LHS))
+                  if (LHSInst->getOperand(0)->hasOneUse()) {
+                    APInt RangeSize = NotB + 2;
+                    APInt NewE = *ConstE + RangeSize;
+                    Value *NewV = Builder.CreateSub(A, ConstantInt::get(A->getType(), NewE));
+                    return Builder.CreateICmp(ICmpInst::ICMP_ULT, NewV,
+                                              ConstantInt::get(A->getType(), -RangeSize));
+                  }
+              }
+            }
+          }
+        }
+      }
       if (Mask & BMask_Mixed)
         return FoldBMixed(NewCC, false);
       if (Mask & BMask_NotMixed) // can be else also

